import{_ as e,o,c as t,a as i}from"./app.076af709.js";const g=JSON.parse('{"title":"bgbba v. Squareblob, Apr 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/bgbba_v_squareblob_apr_2018.md","lastUpdated":1666055355000}'),r={name:"government/court-cases-precedents/bgbba_v_squareblob_apr_2018.md"},n=i('<h1 id="bgbba-v-squareblob-apr-2018" tabindex="-1">bgbba v. Squareblob, Apr 2018 <a class="header-anchor" href="#bgbba-v-squareblob-apr-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Wingzero54 presiding, on 3rd April 2018, bgbba sued for clarification for derelicting Squareblob&#39;s property. Wingzero54 established that citizenship or residency status is not relevant to the question of dereliction.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>bgbba</strong>:</p><blockquote><p>I am bringing a government inquiry against the residency status and plot ownership of Squareblob, as well as a clarification of residency status on the whole.</p></blockquote><blockquote><p>According to the Yoahtlan constitution, citizenship can be removed on the basis of inactivity, however no such provision applies to residency.</p></blockquote><blockquote><p>Squareblob is the leader of Iria and no longer maintains his plot in the undercity of NYC. However, he remains active. The rules for dereliction do not clarify whether or not an active player who doesn&#39;t spend most of their time within NYC can be evicted. As they are written, it leads me to believe that Squareblob is immune to dereliction. I am suing to determine the correct procedure for dereliction, as the dereliction officer. The charter in addition does not establish a clear difference between the jurisdiction of the alcuahtl over citizenship vs residency status, as meat312 brought up earlier in a petition to see the citizenship and residency rules revised. This needs to be addressed.</p></blockquote><p><strong>TheOrangeWizard</strong>:</p><blockquote><p>As the accused, Squareblob has the right to choose a judge</p></blockquote><p><strong>Squareblob</strong>:</p><blockquote><p>Wingzero</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>I am present and willing</p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>Squareblob is no longer active in NYC. He himself has admitted this.</p></blockquote><blockquote><p>It is my duty as dereliction officer to remove inactive things from the city</p></blockquote><blockquote><p>However, the current law doesn&#39;t specify what inactive means in regards to people who are only residents</p></blockquote><blockquote><p>I argue that activity relates specifically to interactions with the Yoahtlan community ingame</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>Thank you BG. Squareblob can you provide a statement regarding your activity within Yoahtl and how your residency is affected by being leader of Iria and spending the majority of your time there?</p></blockquote><p><strong>Squareblob</strong>:</p><blockquote><p>Bg is correct in that I have been inactive for a number of weeks though I wouldn&#39;t necessarily attribute it to doing in game things.</p></blockquote><blockquote><p>Do I need an E-Lawyer? If only for entertainment purposes</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>I am going to admit Square&#39;s activity report for the trial records</p></blockquote><blockquote><blockquote><p>Activity Report for Squareblob</p></blockquote></blockquote><blockquote><blockquote><p>Time online:</p></blockquote></blockquote><blockquote><blockquote><p>Last week: 2:08:39</p></blockquote></blockquote><blockquote><blockquote><p>Two weeks ago: 3:42:04</p></blockquote></blockquote><blockquote><blockquote><p>Three weeks ago: 1 day, 3:27:57</p></blockquote></blockquote><blockquote><blockquote><p>One month ago: 15:54:09</p></blockquote></blockquote><blockquote><blockquote><p>Since records began: 11 days, 7:03:50</p></blockquote></blockquote><blockquote><blockquote><p>9 improperly recorded sessions</p></blockquote></blockquote><blockquote><blockquote><p>Last seen in NYC: 2018-02-19 03:30:42 (43 days, 19:59:40.156457 ago)</p></blockquote></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>43 days ago</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>-&gt;his alt has been in NYC tho (sorry for interupt)</p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>There you go</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>Squareblob How do you respond to BG&#39;s request to derelict you? Do you object to be derelicted? De facto policy is to wait for a 2 week inactivity before derelicting citizens, but you are not a citizen of Yoahtl.</p></blockquote><p><strong>Squareblob</strong>:</p><blockquote><p>It goes without saying I would rather not be derelicted</p></blockquote><p><strong>bgbba</strong>:</p><blockquote><p>My issue here is that this essentially means that residents are unable to be derelicted then</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>Reflecting on Yoahtl&#39;s legal documentation, and court precedence, I turn to the Second Council&#39;s 6.2 decision which states &quot; The Alcuahtl assigns dereliction duty to an individual councillor. This duty cannot be delegated. The longest-inactive players are the first available for eviction and dereliction. The Derelictor and Alcuahtl have discretion over the need to derelict, but but cannot abuse the power. The other two councillors may force the Alcuahtl to reconsider their choice of derelictor, but may not force a resignation without proof of wrongdoing.&quot;</p></blockquote><blockquote><p>This law is the basis for all Yoahtlan derelictions. There is no statement in the law regarding citizenship, residency, or status otherwise. Therefore, there can be no restrictions on the dereliction officer regarding ability to derelict based on residency or citizenship status, because no guidelines are set forth in the legal code for dereliction.</p></blockquote><blockquote><p>Dereliction is a seizure of land on the basis of inactivity, in order to repurpose the land. Dereliction has no basis in citizenship or residency or status otherwise. This is why people who are granted land to build on, such as for embassy&#39;s or foreign owned shops, are allowed to be derelicted (as has been done in the past). It is because dereliction is based on land usage, not residency laws. Therefore, this court finds no restrictions on bgbba&#39;s ability to derelict Squareblob based on his status of a resident instead of citizen.</p></blockquote>',51),a=[n];function s(c,l,b,u,d,p){return o(),t("div",null,a)}const q=e(r,[["render",s]]);export{g as __pageData,q as default};
